import React, { useMemo, useState } from "react";
import axios from "axios";
import { Link, useLocation, useNavigate } from "react-router-dom";
import { BookingRecord, Bus, PassengerDetail } from "../types";

const API_BASES = ["http://localhost:5000/api", "http://127.0.0.1:5000/api"];

type PaymentState = {
  busId?: string;
  bus?: Bus;
  selectedSeats?: number[];
  passengerDetails?: PassengerDetail[];
  boardingPoint?: string;
  droppingPoint?: string;
  totalPrice?: number;
};

const Payment: React.FC = () => {
  const location = useLocation();
  const navigate = useNavigate();
  const state = (location.state || {}) as PaymentState;

  const [paymentMethod, setPaymentMethod] = useState("UPI");
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  const canPay = useMemo(() => {
    return Boolean(
      state.busId &&
        state.bus &&
        state.selectedSeats &&
        state.selectedSeats.length >= 1 &&
        state.selectedSeats.length <= 4 &&
        state.passengerDetails &&
        state.passengerDetails.length === state.selectedSeats.length &&
        state.boardingPoint &&
        state.droppingPoint
    );
  }, [state]);

  const handlePayment = async () => {
    if (!canPay || !state.busId || !state.selectedSeats || !state.passengerDetails || !state.bus || !state.boardingPoint || !state.droppingPoint) {
      return;
    }

    setLoading(true);
    setError("");

    for (const base of API_BASES) {
      try {
        const response = await axios.post<{ booking: BookingRecord }>(`${base}/bookings`, {
          busId: state.busId,
          selectedSeats: state.selectedSeats,
          passengerDetails: state.passengerDetails,
          boardingPoint: state.boardingPoint,
          droppingPoint: state.droppingPoint,
          paymentMethod
        });

        navigate("/confirmation", {
          state: {
            booking: response.data.booking,
            bus: state.bus,
            successMessage: "Booking Successful"
          }
        });
        return;
      } catch (requestError) {
        console.error(`Payment/booking failed via ${base}`, requestError);

        if (axios.isAxiosError(requestError) && requestError.response?.data?.message) {
          setError(String(requestError.response.data.message));
          setLoading(false);
          return;
        }
      }
    }

    setError("Could not connect to backend. Start it with: cd backend && node server.js");
    setLoading(false);
  };

  if (!canPay || !state.bus) {
    return (
      <section className="rounded-2xl bg-white p-8 text-center shadow-travel ring-1 ring-slate-200">
        <h2 className="text-2xl font-bold text-slate-900">Payment details missing</h2>
        <p className="mt-2 text-slate-600">Please select seats, boarding point, and passenger details first.</p>
        <Link to="/buses" className="mt-4 inline-block rounded-lg bg-blue-600 px-4 py-2 text-white">
          Back to Buses
        </Link>
      </section>
    );
  }

  return (
    <section className="grid gap-6 lg:grid-cols-[1.5fr_1fr]">
      <div className="rounded-2xl bg-white p-6 shadow-travel ring-1 ring-slate-200">
        <h2 className="text-2xl font-bold text-slate-900">Payment</h2>
        <p className="mt-1 text-sm text-slate-600">{state.bus.operatorName} | {state.bus.departureCity} {"->"} {state.bus.arrivalCity}</p>

        <div className="mt-5 grid gap-3 sm:grid-cols-2">
          <div className="rounded-xl bg-slate-50 p-4 ring-1 ring-slate-200">
            <p className="text-xs uppercase text-slate-500">Boarding Point</p>
            <p className="mt-1 text-sm font-semibold text-slate-900">{state.boardingPoint}</p>
          </div>
          <div className="rounded-xl bg-slate-50 p-4 ring-1 ring-slate-200">
            <p className="text-xs uppercase text-slate-500">Dropping Point</p>
            <p className="mt-1 text-sm font-semibold text-slate-900">{state.droppingPoint}</p>
          </div>
        </div>

        <div className="mt-5 space-y-3">
          {["UPI", "Card", "NetBanking"].map((method) => (
            <label
              key={method}
              className={`flex cursor-pointer items-center gap-3 rounded-lg border p-3 ${paymentMethod === method ? "border-blue-500 bg-blue-50" : "border-slate-300"}`}
            >
              <input type="radio" name="paymentMethod" value={method} checked={paymentMethod === method} onChange={(e) => setPaymentMethod(e.target.value)} />
              <span className="font-medium text-slate-800">{method}</span>
            </label>
          ))}
        </div>

        <button
          type="button"
          onClick={handlePayment}
          disabled={loading}
          className="mt-6 w-full rounded-lg bg-blue-600 px-4 py-2.5 font-semibold text-white transition hover:bg-blue-700 disabled:cursor-not-allowed disabled:bg-blue-300"
        >
          {loading ? "Processing..." : "Pay and Confirm Booking"}
        </button>
        {error ? <p className="mt-3 text-sm font-medium text-red-600">{error}</p> : null}
      </div>

      <aside className="h-fit rounded-2xl bg-white p-6 shadow-travel ring-1 ring-slate-200">
        <h3 className="text-lg font-semibold text-slate-900">Payment Summary</h3>
        <div className="mt-4 space-y-2 text-sm text-slate-700">
          <p><span className="font-medium">Seats:</span> {state.selectedSeats?.join(", ")}</p>
          <p><span className="font-medium">Passengers:</span> {state.passengerDetails?.length}</p>
          <p><span className="font-medium">Boarding:</span> {state.boardingPoint}</p>
          <p><span className="font-medium">Dropping:</span> {state.droppingPoint}</p>
          <p className="flex items-center justify-between border-t border-slate-200 pt-3 text-lg font-bold text-blue-700"><span>Total</span><span>INR {state.totalPrice}</span></p>
        </div>
      </aside>
    </section>
  );
};

export default Payment;
